import { LimeplayMediaPlayer } from "@/registry/default/blocks/basic-player/components/media-player"

export default function Page() {
  return (
    <section className="flex h-dvh w-dvw bg-black">
      <LimeplayMediaPlayer src="https://ad391cc0d55b44c6a86d232548adc225.mediatailor.us-east-1.amazonaws.com/v1/master/d02fedbbc5a68596164208dd24e9b48aa60dadc7/singssai/master.m3u8" />
    </section>
  )
}

"use client"

import {
  CircleNotchIcon,
  PauseIcon,
  PlayIcon,
  RepeatIcon,
} from "@phosphor-icons/react"

import { Button } from "@/components/ui/button"
import { usePlaybackStore } from "@/registry/default/hooks/use-playback"
import { PlaybackControl } from "@/registry/default/ui/playback-control"

export function PlaybackStateControl() {
  const status = usePlaybackStore((state) => state.status)

  return (
    <Button asChild size="icon" variant="ghost">
      <PlaybackControl>
        {status === "playing" ? (
          <PauseIcon size={18} weight="fill" />
        ) : status === "ended" ? (
          <RepeatIcon size={18} />
        ) : status === "buffering" ? (
          <CircleNotchIcon className="animate-spin" size={18} weight="bold" />
        ) : (
          <PlayIcon size={18} weight="fill" />
        )}
      </PlaybackControl>
    </Button>
  )
}

"use client"

import { useEffect } from "react"

import { useMediaStore } from "@/registry/default/hooks/use-media"
import { usePlayerStore } from "@/registry/default/hooks/use-player"
import { Media } from "@/registry/default/ui/media"

export function MediaElement({ src }: { src: string }) {
  const player = usePlayerStore((state) => state.instance)
  const mediaElement = useMediaStore((state) => state.mediaElement)

  useEffect(() => {
    if (player && mediaElement) {
      if (src) {
        try {
          const parsedUrl = new URL(src)

          if (!["http:", "https:"].includes(parsedUrl.protocol)) {
            throw new Error("Invalid URL protocol")
          }
        } catch (error) {
          console.error(
            "Invalid playback URL:",
            error instanceof Error ? error.message : "Unknown error"
          )
        }
      }

      void player
        .load(src)
        .then(() => {
          console.debug("[limeplay] media loaded")
        })
        .catch((error: unknown) => {
          console.error("[limeplay] error loading media:", error)
        })
    }
  }, [player, mediaElement, src])

  return (
    <Media
      as="video"
      autoPlay={false}
      className="size-full bg-background object-cover"
      loop
      muted
    />
  )
}
